#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

// Writes site/version.js with a fresh build timestamp on every build path —
// independent of whether the model catalogue was regenerated. This means a
// static-only rebuild (site changes, no AWS fetch) still bumps the footer.
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const buildVersion = `${now.getFullYear()}.${pad(now.getMonth() + 1)}.${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

const output = [
    '// Auto-generated by build/stamp-version.js — do not edit manually',
    `const BUILD_VERSION = '${buildVersion}';`,
    ''
].join('\n');

fs.writeFileSync(path.join(__dirname, '..', 'site', 'version.js'), output);
console.log(`Stamped site/version.js — ${buildVersion}`);
